import{_ as t,o,c as l,au as s}from"./chunks/framework.Bpqx6pAq.js";const m=JSON.parse('{"title":"Style utilities","description":"","frontmatter":{},"headers":[],"relativePath":"api/map/utilities/utils.style.md","filePath":"api/map/utilities/utils.style.md"}'),a={name:"api/map/utilities/utils.style.md"};function i(r,e,n,c,d,y){return o(),l("div",null,[...e[0]||(e[0]=[s('<h1 id="style-utilities" tabindex="-1">Style utilities <a class="header-anchor" href="#style-utilities" aria-label="Permalink to &quot;Style utilities&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This module provides constants and functions for converting between different map style representations (KDK internal style, Simple Style Spec, Leaflet/Cesium engine styles), and for generating and parsing style template expressions used for conditional feature styling.</p><h2 id="constants" tabindex="-1">Constants <a class="header-anchor" href="#constants" aria-label="Permalink to &quot;Constants&quot;">​</a></h2><h3 id="style-mapping-objects" tabindex="-1">Style Mapping Objects <a class="header-anchor" href="#style-mapping-objects" aria-label="Permalink to &quot;Style Mapping Objects&quot;">​</a></h3><p>These objects map property names between different style formats. They are used internally by the conversion functions.</p><table tabindex="0"><thead><tr><th>Constant</th><th>Description</th></tr></thead><tbody><tr><td><code>IconStyleToSimpleStyle</code></td><td>Maps KDK icon style keys to Simple Style Spec keys.</td></tr><tr><td><code>PointStyleToSimpleStyle</code></td><td>Maps KDK point style keys to Simple Style Spec keys.</td></tr><tr><td><code>SimpleStyleToPointStyle</code></td><td>Maps Simple Style Spec keys to KDK point style keys.</td></tr><tr><td><code>PointStyleTemplateMappings</code></td><td>Maps Simple Style Spec keys to KDK style template paths for point features.</td></tr><tr><td><code>LineStyleToSimpleStyle</code></td><td>Maps KDK line style keys to Simple Style Spec keys.</td></tr><tr><td><code>SimpleStyleToLineStyle</code></td><td>Maps Simple Style Spec keys to KDK line style keys.</td></tr><tr><td><code>LineStyleTemplateMappings</code></td><td>Maps Simple Style Spec keys to KDK style template paths for line features.</td></tr><tr><td><code>PolygonStyleToSimpleStyle</code></td><td>Maps KDK polygon style keys to Simple Style Spec keys.</td></tr><tr><td><code>SimpleStyleToPolygonStyle</code></td><td>Maps Simple Style Spec keys to KDK polygon style keys.</td></tr><tr><td><code>PolygonStyleTemplateMappings</code></td><td>Maps Simple Style Spec keys to KDK style template paths for polygon features.</td></tr><tr><td><code>SimpleStyleNumbers</code></td><td>List of Simple Style Spec property names that should be parsed as numbers.</td></tr><tr><td><code>DefaultStyle</code></td><td>The default KDK style object covering <code>point</code>, <code>line</code>, <code>polygon</code>, <code>leaflet.cluster</code>, and <code>cesium.cluster</code> defaults.</td></tr><tr><td><code>kmlStyleSpecialProperties</code></td><td>KML-specific property names treated specially during import (<code>extrude</code>, <code>altitudeMode</code>).</td></tr></tbody></table><h2 id="conversion-functions" tabindex="-1">Conversion Functions <a class="header-anchor" href="#conversion-functions" aria-label="Permalink to &quot;Conversion Functions&quot;">​</a></h2><h3 id="convertstyle-style-mapping-asnumber" tabindex="-1"><code>convertStyle(style, mapping, asNumber?)</code> <a class="header-anchor" href="#convertstyle-style-mapping-asnumber" aria-label="Permalink to &quot;`convertStyle(style, mapping, asNumber?)`&quot;">​</a></h3><p>Converts a style object by remapping its keys according to a mapping object.</p><ul><li><strong>Parameters:</strong><ul><li><code>style</code> <em>(Object)</em>: The source style object.</li><li><code>mapping</code> <em>(Object)</em>: A <code>{ sourceKey: targetPath }</code> mapping object.</li><li><code>asNumber</code> <em>(Array, optional)</em>: Target key names whose values should be cast to numbers.</li></ul></li><li><strong>Returns:</strong> <code>Object</code> — A new style object with remapped keys.</li></ul><hr><h3 id="convertsimplestylecolors-style" tabindex="-1"><code>convertSimpleStyleColors(style)</code> <a class="header-anchor" href="#convertsimplestylecolors-style" aria-label="Permalink to &quot;`convertSimpleStyleColors(style)`&quot;">​</a></h3><p>Converts Quasar palette color names (e.g. <code>&#39;primary&#39;</code>) in <code>stroke</code>, <code>fill</code>, and <code>marker-color</code> properties to their HTML color equivalents.</p><ul><li><strong>Returns:</strong> <code>Object</code> — The mutated style object.</li></ul><hr><h3 id="convertpointstyletosimplestyle-style-convertsimplestyletopointstyle-style" tabindex="-1"><code>convertPointStyleToSimpleStyle(style)</code> / <code>convertSimpleStyleToPointStyle(style)</code> <a class="header-anchor" href="#convertpointstyletosimplestyle-style-convertsimplestyletopointstyle-style" aria-label="Permalink to &quot;`convertPointStyleToSimpleStyle(style)` / `convertSimpleStyleToPointStyle(style)`&quot;">​</a></h3><p>Converts between KDK point style and Simple Style Spec.</p><hr><h3 id="convertlinestyletosimplestyle-style-convertsimplestyletolinestyle-style" tabindex="-1"><code>convertLineStyleToSimpleStyle(style)</code> / <code>convertSimpleStyleToLineStyle(style)</code> <a class="header-anchor" href="#convertlinestyletosimplestyle-style-convertsimplestyletolinestyle-style" aria-label="Permalink to &quot;`convertLineStyleToSimpleStyle(style)` / `convertSimpleStyleToLineStyle(style)`&quot;">​</a></h3><p>Converts between KDK line style and Simple Style Spec.</p><hr><h3 id="convertpolygonstyletosimplestyle-style-convertsimplestyletopolygonstyle-style" tabindex="-1"><code>convertPolygonStyleToSimpleStyle(style)</code> / <code>convertSimpleStyleToPolygonStyle(style)</code> <a class="header-anchor" href="#convertpolygonstyletosimplestyle-style-convertsimplestyletopolygonstyle-style" aria-label="Permalink to &quot;`convertPolygonStyleToSimpleStyle(style)` / `convertSimpleStyleToPolygonStyle(style)`&quot;">​</a></h3><p>Converts between KDK polygon style and Simple Style Spec (includes stroke conversion).</p><h2 id="shape-helper-functions" tabindex="-1">Shape Helper Functions <a class="header-anchor" href="#shape-helper-functions" aria-label="Permalink to &quot;Shape Helper Functions&quot;">​</a></h2><h3 id="getstyletype-geometrytype" tabindex="-1"><code>getStyleType(geometryType)</code> <a class="header-anchor" href="#getstyletype-geometrytype" aria-label="Permalink to &quot;`getStyleType(geometryType)`&quot;">​</a></h3><p>Returns the KDK style category string for a GeoJSON geometry type.</p><ul><li><strong>Parameters:</strong><ul><li><code>geometryType</code> <em>(string)</em>: GeoJSON geometry type (e.g. <code>&#39;Point&#39;</code>, <code>&#39;LineString&#39;</code>, <code>&#39;Polygon&#39;</code>).</li></ul></li><li><strong>Returns:</strong> <code>&#39;point&#39;</code> | <code>&#39;line&#39;</code> | <code>&#39;polygon&#39;</code> | <code>undefined</code></li></ul><hr><h3 id="getshapefrompointstyle-style-size" tabindex="-1"><code>getShapeFromPointStyle(style, size?)</code> <a class="header-anchor" href="#getshapefrompointstyle-style-size" aria-label="Permalink to &quot;`getShapeFromPointStyle(style, size?)`&quot;">​</a></h3><p>Builds a KShape-compatible descriptor from a point style. Normalises the stroke width if greater than 1.</p><ul><li><strong>Returns:</strong> <code>Object</code></li></ul><hr><h3 id="getshapefromlinestyle-style-size" tabindex="-1"><code>getShapeFromLineStyle(style, size?)</code> <a class="header-anchor" href="#getshapefromlinestyle-style-size" aria-label="Permalink to &quot;`getShapeFromLineStyle(style, size?)`&quot;">​</a></h3><p>Builds a KShape-compatible descriptor (polyline shape) from a line style.</p><ul><li><strong>Returns:</strong> <code>Object</code></li></ul><hr><h3 id="getshapefrompolygonstyle-style-size" tabindex="-1"><code>getShapeFromPolygonStyle(style, size?)</code> <a class="header-anchor" href="#getshapefrompolygonstyle-style-size" aria-label="Permalink to &quot;`getShapeFromPolygonStyle(style, size?)`&quot;">​</a></h3><p>Builds a KShape-compatible descriptor (polygon shape) from a polygon style.</p><ul><li><strong>Returns:</strong> <code>Object</code></li></ul><h2 id="template-functions" tabindex="-1">Template Functions <a class="header-anchor" href="#template-functions" aria-label="Permalink to &quot;Template Functions&quot;">​</a></h2><h3 id="getdefaultstylefromtemplates-options" tabindex="-1"><code>getDefaultStyleFromTemplates(options)</code> <a class="header-anchor" href="#getdefaultstylefromtemplates-options" aria-label="Permalink to &quot;`getDefaultStyleFromTemplates(options)`&quot;">​</a></h3><p>Extracts the default (else-branch) values from a style object that may contain EJS template expressions of the form <code>&lt;% if (...) { %&gt;value&lt;% } else { %&gt;default&lt;% } %&gt;</code>.</p><ul><li><strong>Parameters:</strong><ul><li><code>options</code> <em>(Object)</em>: A style object potentially containing template strings.</li></ul></li><li><strong>Returns:</strong> <code>Object</code> — A plain style object with only the default values.</li></ul><hr><h3 id="generatestyletemplates-defaultstyle-styles-dotify" tabindex="-1"><code>generateStyleTemplates(defaultStyle, styles, dotify?)</code> <a class="header-anchor" href="#generatestyletemplates-defaultstyle-styles-dotify" aria-label="Permalink to &quot;`generateStyleTemplates(defaultStyle, styles, dotify?)`&quot;">​</a></h3><p>Generates EJS style template expressions for each style property based on a set of conditional filter styles and a default style.</p><ul><li><strong>Parameters:</strong><ul><li><code>defaultStyle</code> <em>(Object)</em>: The default <code>{ point, line, polygon }</code> style applied when no condition matches.</li><li><code>styles</code> <em>(Array)</em>: An array of <code>{ conditions, values }</code> objects: <ul><li><code>conditions</code> <em>(Array)</em>: Each condition has <code>{ booleanOperator, property, comparisonOperator, value }</code>.</li><li><code>values</code> <em>(Object)</em>: The <code>{ point, line, polygon }</code> style to apply when the conditions are met.</li></ul></li><li><code>dotify</code> <em>(boolean, default <code>true</code>)</em>: When <code>true</code>, output keys use dot notation (e.g. <code>&#39;style.point.color&#39;</code>).</li></ul></li><li><strong>Returns:</strong> <code>Object</code> — An object where each key is a style property path and each value is either an EJS template string or a plain value. A <code>template</code> array lists the property paths that require template evaluation.</li></ul><hr><h3 id="filterquerytoconditions-query" tabindex="-1"><code>filterQueryToConditions(query)</code> <a class="header-anchor" href="#filterquerytoconditions-query" aria-label="Permalink to &quot;`filterQueryToConditions(query)`&quot;">​</a></h3><p>Parses a MongoDB-style filter query object into an array of condition descriptors for use with <code>generateStyleTemplates</code>.</p><ul><li><strong>Parameters:</strong><ul><li><code>query</code> <em>(Object)</em>: A MongoDB query object (supports <code>$and</code>, <code>$or</code>, <code>$eq</code>, <code>$ne</code>, <code>$gt</code>, <code>$gte</code>, <code>$lt</code>, <code>$lte</code>, <code>$in</code>, <code>$nin</code>).</li></ul></li><li><strong>Returns:</strong> <code>Array</code> — An array of <code>{ index, booleanOperator, property, comparisonOperator, value }</code> objects.</li></ul>',52)])])}const u=t(a,[["render",i]]);export{m as __pageData,u as default};
